#include <stdlib.h>
#include <stdio.h>

void cleanup(void) {
 printf("This will NOT be printed\n");
}

int main() {
 atexit(cleanup);
 printf("Calling abort()...\n");
 abort(); // Program terminates here
 printf("This line never executes\n");
 return 0;
}

#include <stdlib.h>
#include <stdio.h>

void my_cleanup(void) {
 printf("Cleanup function called\n");
}

int main() {
 atexit(my_cleanup);

 // Uncomment one of the following:
 // exit(0); // Calls cleanup, flushes buffers
 // abort(); // Does NOT call cleanup
 // _Exit(0); // Does NOT call cleanup

 return 0;
}

#include <signal.h>
#include <stdlib.h>
#include <stdio.h>

void sigabrt_handler(int signum) {
 printf("Caught SIGABRT signal!\n");
 // If we return, abort() will still terminate
}

int main() {
 signal(SIGABRT, sigabrt_handler);
 printf("Calling abort()...\n");
 abort();
 printf("This never prints\n");
 return 0;
}

#include <stdlib.h>
#include <stdio.h>

void handle_fatal_error(const char* message) {
 fprintf(stderr, "FATAL: %s\n", message);
 fprintf(stderr,"Generating core dump for debugging...\n");
 abort(); // Abnormal termination
}

int* safe_malloc(size_t size) {
 void* ptr = malloc(size);
 if (ptr == NULL) {
 handle_fatal_error("Memory allocation failed");
 }
 return ptr;
}

int main() {
 int* data = safe_malloc(100);
 printf("Allocated: %p\n", (void*)data);
 return 0;
}
